const KEYWORDS = ['장애인', '문화예술', '예술', 'AI', '인공지능', '콘텐츠', '교육', '복지', '사회적기업'];
const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);
function fmt(d) {
  const p = (n) => String(n).padStart(2, '0');
  return `${d.getFullYear()}${p(d.getMonth()+1)}${p(d.getDate())}${p(d.getHours())}${p(d.getMinutes())}`;
}
return [{ json: { keywords: KEYWORDS, inqryBgnDt: fmt(yesterday), inqryEndDt: fmt(now) } }];

const keywords = $('검색 조건 설정').first().json.keywords;
function extractItems(nodeOutput, category) {
  try {
    const body = nodeOutput?.json;
    let items = body?.response?.body?.items || [];
    if (!Array.isArray(items)) items = items ? [items] : [];
    return items.map(it => ({ ...it, _category: category }));
  } catch(e) { return []; }
}
const allItems = [
  ...extractItems($input.all()[0], '용역'),
  ...extractItems($input.all()[1], '물품'),
  ...extractItems($input.all()[2], '공사')
];
const seen = new Set();
const unique = allItems.filter(it => { if (seen.has(it.bidNtceNo)) return false; seen.add(it.bidNtceNo); return true; });
const matched = unique.filter(it => keywords.some(kw => (it.bidNtceNm||'').includes(kw)));
const price = (it) => Number(it.presmptPrce || it.asignBdgtAmt || 0);
return matched.map(it => ({ json: {
  공고명: it.bidNtceNm,
  공고번호: it.bidNtceNo,
  공고순번: it.bidNtceOrd || '00',
  분류: it._category,
  수요기관: it.dminsttNm || it.ntceInsttNm || '-',
  공고일: it.bidNtceDt,
  마감일시: it.bidClseDt,
  추정가격원: price(it),
  추정가격: price(it) > 0 ? price(it).toLocaleString('ko-KR')+'원' : '미공개',
  수의계약가능: price(it) > 0 && price(it) <= 20000000,
  상세URL: `https://www.g2b.go.kr/ep/invitation/publish/bidInvitDtlPublish.do?bidno=${it.bidNtceNo}&bidseq=${it.bidNtceOrd||'00'}`
}}));

const items = $input.all().map(i => i.json);
const suui = items.filter(it => it.수의계약가능);
return [{ json: { all: items, suui, suuiCount: suui.length, totalCount: items.length } }];

// Claude API 호출용 프롬프트 준비
const classified = $('수의계약 분류').first().json;
const items = classified.all.slice(0, 20);
const prompt = `당신은 나라장터 입찰 전문가입니다.

회사 특성:
- 장애인기업 + 예비사회적기업
- 수의계약 우선 대상(2천만원 이하)
- 주요 역량: 문화예술, 콘텐츠, AI, 교육, 복지서비스

공고 목록:
${JSON.stringify(items.map(it=>({공고번호:it.공고번호,공고명:it.공고명,수요기관:it.수요기관,추정가격:it.추정가격,수의계약가능:it.수의계약가능})),null,2)}

JSON 배열로만 응답하세요 (다른 텍스트 없이):
[{"공고번호":"...","추천여부":"추천|보류|제외","점수":0~100,"이유":"한줄이유"}]`;
return [{ json: { prompt } }];

const body = $input.first().json;
let items = body?.response?.body?.items || [];
if (!Array.isArray(items)) items = items ? [items] : [];
const prices = items.map(it => Number(it.sucsfbidAmt||0)).filter(p=>p>0).sort((a,b)=>a-b);
let analysis = { 샘플수: 0, 안정형: null, 중간형: null, 공격형: null, 낙찰률평균: null };
if (prices.length >= 3) {
  const avg = prices.reduce((s,p)=>s+p,0)/prices.length;
  const min = prices[0];
  analysis = {
    샘플수: prices.length,
    안정형: Math.round(avg).toLocaleString('ko-KR')+'원',
    중간형: Math.round(avg*0.97).toLocaleString('ko-KR')+'원',
    공격형: Math.round((avg+min)/2*0.95).toLocaleString('ko-KR')+'원',
    낙찰률평균: (avg/prices[prices.length-1]*100).toFixed(1)+'%'
  };
}
return [{ json: { 낙찰이력분석: analysis } }];

// Claude 응답(index 0) + 낙찰가 분석(index 1) 병합
const inputs = $input.all();
const aiResponse = inputs[0]?.json;
const aiRaw = aiResponse?.content?.[0]?.text || '';
const 낙찰이력분析 = inputs[1]?.json?.낙찰이력분析 || { 샘플수: 0 };
const classified = $('수의계약 분류').first().json;

let aiResults = [];
try {
  const match = aiRaw.match(/\[.*\]/s);
  if (match) aiResults = JSON.parse(match[0]);
} catch(e) {}

const aiMap = {};
aiResults.forEach(r => { aiMap[r.공고번호] = r; });

const enriched = classified.all.map(it => ({
  ...it,
  AI추천: aiMap[it.공고번호]?.추천여부 || '미분析',
  AI점수: aiMap[it.공고번호]?.점수 || 0,
  AI이유: aiMap[it.공고번호]?.이유 || ''
}));

const 추천 = enriched.filter(it => it.AI추천 === '추천').sort((a,b) => b.AI점수 - a.AI점수);
const 보류 = enriched.filter(it => it.AI추천 === '보류');
const 수의 = enriched.filter(it => it.수의계약가능);

return [{ json: { 추천, 보류, 수의, 낙찰이력분析, totalCount: enriched.length } }];

const { 추천, 보류, 수의, 낙찰이력분석, totalCount } = $input.first().json;
const today = new Date().toLocaleDateString('ko-KR');

function tableRows(items) {
  if (!items || !items.length) return '<tr><td colspan="6" style="padding:12px;text-align:center;color:#999;">해당 공고 없음</td></tr>';
  return items.map((it,i) => `<tr style="background:${i%2===0?'#fff':'#f9f9f9'}"><td style="padding:8px;border:1px solid #e0e0e0;">${i+1}</td><td style="padding:8px;border:1px solid #e0e0e0;"><a href="${it.상세URL}" style="color:#1a73e8;">${it.공고명}</a></td><td style="padding:8px;border:1px solid #e0e0e0;font-size:12px;">${it.수요기관}</td><td style="padding:8px;border:1px solid #e0e0e0;font-size:12px;">${it.마감일시}</td><td style="padding:8px;border:1px solid #e0e0e0;">${it.추정가격}</td><td style="padding:8px;border:1px solid #e0e0e0;font-size:12px;color:${it.AI추천==='추천'?'#2e7d32':'#666'}">${it.AI점수?it.AI점수+'점':'-'}${it.AI이유?' / '+it.AI이유:''}</td></tr>`).join('');
}

const thead = '<tr style="background:#1a73e8;color:#fff;"><th style="padding:8px;">#</th><th style="padding:8px;">공고명</th><th style="padding:8px;">수요기관</th><th style="padding:8px;">마감</th><th style="padding:8px;">추정가격</th><th style="padding:8px;">AI판단</th></tr>';

const a = 낙찰이력분석;
const analysisBlock = (a && a.샘플수 > 0)
  ? `<h3 style="color:#e65100;">📊 낙찰가 분석 (샘플 ${a.샘플수}건)</h3><table style="border-collapse:collapse;"><tr><td style="padding:6px 16px;">✅ 안정형</td><td><b>${a.안정형}</b></td></tr><tr><td style="padding:6px 16px;">⚡ 중간형</td><td><b>${a.중간형}</b></td></tr><tr><td style="padding:6px 16px;">🎯 공격형</td><td><b>${a.공격형}</b></td></tr><tr><td style="padding:6px 16px;">낙찰률</td><td>${a.낙찰률평균}</td></tr></table>`
  : '<p style="color:#999;">낙찰 이력 데이터 부족</p>';

const suuiAlert = (수의 && 수의.length > 0)
  ? `<div style="background:#e8f5e9;border-left:4px solid #4caf50;padding:12px;margin:16px 0;"><strong>🤝 수의계약 가능 ${수의.length}건</strong> (2천만원 이하 — 장애인기업 우선 대상)<br/><br/>${수의.map(it=>`• <a href="${it.상세URL}">${it.공고명}</a> (${it.추정가격})`).join('<br/>')}</div>`
  : '';

const html = `<div style="font-family:Apple SD Gothic Neo,Malgun Gothic,sans-serif;max-width:900px;"><h2 style="color:#1a73e8;">📋 나라장터 입찰공고 일일 리포트 (${today})</h2><p>전체 <strong>${totalCount}건</strong> | AI 추천 <strong style="color:#2e7d32;">${(추천||[]).length}건</strong> | 보류 <strong style="color:#f57c00;">${(보류||[]).length}건</strong> | 수의계약 <strong style="color:#4caf50;">${(수의||[]).length}건</strong></p>${suuiAlert}<h3 style="color:#2e7d32;">✅ AI 추천 공고</h3><table style="border-collapse:collapse;width:100%;font-size:13px;">${thead}${tableRows(추천)}</table>${analysisBlock}<h3 style="color:#f57c00;">⏳ 보류 공고</h3><table style="border-collapse:collapse;width:100%;font-size:13px;">${thead}${tableRows(보류)}</table><hr style="margin-top:24px;"/><p style="font-size:11px;color:#999;">자동 발송 — (주)미미 나라장터 모니터링 | n8n</p></div>`;

return [{ json: { subject: `[나라장터] 추천 ${(추천||[]).length}건 · 수의 ${(수의||[]).length}건 — ${today}`, html } }];
